(function () {'use strict';const STORAGE_KEY = 'vetcare_theme';function getInitialTheme() {try {const saved = localStorage.getItem(STORAGE_KEY);if (saved === 'dark' || saved === 'light') return saved;} catch (e) { }if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {return 'dark';}return 'light';}function applyTheme(theme) {document.documentElement.setAttribute('data-theme', theme);try { localStorage.setItem(STORAGE_KEY, theme); } catch (e) {}}function toggleTheme() {const current = document.documentElement.getAttribute('data-theme') || 'light';const next = current === 'dark' ? 'light' : 'dark';applyTheme(next);if (window.showToast) {const msg = next === 'dark' ? 'Включена тёмная тема' : 'Включена светлая тема';window.showToast(msg, 'info', 2000);}}applyTheme(getInitialTheme());document.addEventListener('DOMContentLoaded', function () {const toggle = document.getElementById('themeToggle');if (toggle) {toggle.addEventListener('click', toggleTheme);}});window.showToast = function (message, type, duration) {type = type || 'info';if (duration === undefined) duration = 4000;let container = document.getElementById('toastContainer');if (!container) {container = document.createElement('div');container.id = 'toastContainer';container.className = 'toast-container';document.body.appendChild(container);}const icons = {success: '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><path d="m9 12 2 2 4-4"/></svg>',error: '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><path d="m15 9-6 6"/><path d="m9 9 6 6"/></svg>',info: '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4"/><path d="M12 8h.01"/></svg>',warning: '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"/><path d="M12 9v4"/><path d="M12 17h.01"/></svg>',};const closeIcon = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>';const toast = document.createElement('div');toast.className = 'toast toast-' + type;const iconDiv = document.createElement('div');iconDiv.className = 'toast-icon';iconDiv.innerHTML = icons[type] || icons.info;const bodyDiv = document.createElement('div');bodyDiv.className = 'toast-body';bodyDiv.textContent = message;const closeBtn = document.createElement('button');closeBtn.className = 'toast-close';closeBtn.type = 'button';closeBtn.setAttribute('aria-label', 'Закрыть');closeBtn.innerHTML = closeIcon;toast.appendChild(iconDiv);toast.appendChild(bodyDiv);toast.appendChild(closeBtn);container.appendChild(toast);function removeToast() {toast.classList.add('toast-hiding');setTimeout(function () {if (toast.parentNode) toast.parentNode.removeChild(toast);}, 300);}closeBtn.addEventListener('click', removeToast);if (duration > 0) {setTimeout(removeToast, duration);}return toast;};window.toastSuccess = function (msg, duration) { return window.showToast(msg, 'success', duration); };window.toastError = function (msg, duration) { return window.showToast(msg, 'error', duration); };window.toastInfo = function (msg, duration) { return window.showToast(msg, 'info', duration); };window.toastWarning = function (msg, duration) { return window.showToast(msg, 'warning', duration); };document.addEventListener('DOMContentLoaded', function () {const alerts = document.querySelectorAll('.alert');alerts.forEach(function (alert) {const text = alert.textContent.trim();if (!text) return;let type = 'info';if (alert.classList.contains('alert-success')) type = 'success';if (alert.classList.contains('alert-danger')) type = 'error';if (alert.classList.contains('alert-info')) type = 'info';window.showToast(text, type, 5000);alert.remove();});});})();